import{_ as a,o as t,c as l,a0 as i}from"./chunks/framework.AQcSKqPn.js";const u=JSON.parse('{"title":"钢之炼金术师 FULLMETAL ALCHEMIST","description":"","frontmatter":{"type":"entity","title":"钢之炼金术师 FULLMETAL ALCHEMIST","tags":["anime","fullmetal-alchemist","brotherhood"],"related":["edward-elric","alphonse-elric","human-transmutation","equivalent-exchange"],"sources":["anime/5114.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"entities/钢之炼金术师-fullmetal-alchemist.md","filePath":"entities/钢之炼金术师-fullmetal-alchemist.md","lastUpdated":1784685724000}'),r={name:"entities/钢之炼金术师-fullmetal-alchemist.md"};function n(o,e,s,h,c,m){return t(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="钢之炼金术师-fullmetal-alchemist" tabindex="-1">钢之炼金术师 FULLMETAL ALCHEMIST <a class="header-anchor" href="#钢之炼金术师-fullmetal-alchemist" aria-label="Permalink to &quot;钢之炼金术师 FULLMETAL ALCHEMIST&quot;">​</a></h1><ul><li><strong>发布日期</strong>: 2026年07月10日 《钢之炼金术师 FULLMETAL ALCHEMIST》（Fullmetal Alchemist: Brotherhood）是2009年播出的日本动画，改编自荒川弘的同名漫画。该作品在MyAnimeList上获得9.11的高分，被广泛认为是有史以来最伟大的动画之一。</li></ul><h2 id="元数据" tabindex="-1">元数据 <a class="header-anchor" href="#元数据" aria-label="Permalink to &quot;元数据&quot;">​</a></h2><ul><li><strong>评分</strong>: 9.11</li><li><strong>集数</strong>: 64</li><li><strong>状态</strong>: 已完结</li><li><strong>类型</strong>: 动作、冒险、剧情、奇幻</li><li><strong>首播年份</strong>: 2009</li></ul><h2 id="剧情概要" tabindex="-1">剧情概要 <a class="header-anchor" href="#剧情概要" aria-label="Permalink to &quot;剧情概要&quot;">​</a></h2><p>故事围绕艾尔利克兄弟——爱德华和阿尔冯斯展开。兄弟俩因试图通过禁忌的人体炼成复活已故的母亲，而付出了惨痛的代价：阿尔冯斯失去了整个身体，爱德华失去了一条腿和一只手臂。为了将阿尔冯斯的灵魂固定在物质世界，爱德华将其束缚在一副巨大的盔甲中。兄弟二人从此踏上寻找贤者之石的旅程，以期恢复失去的身体。</p><h2 id="核心主题" tabindex="-1">核心主题 <a class="header-anchor" href="#核心主题" aria-label="Permalink to &quot;核心主题&quot;">​</a></h2><p>作品深入探讨了<a href="/llm-wiki/concepts/等价交换">equivalent-exchange</a>原则——炼金术的基本法则，也是贯穿全剧的哲学框架。禁忌的<a href="/llm-wiki/concepts/人体炼成">human-transmutation</a>作为故事的触发事件，引出了关于生命、牺牲、代价与人性的深刻思考。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/llm-wiki/entities/爱德华艾尔利克">edward-elric</a> — 爱德华·艾尔利克</li><li><a href="/llm-wiki/entities/阿尔冯斯艾尔利克">alphonse-elric</a> — 阿尔冯斯·艾尔利克</li><li><a href="/llm-wiki/concepts/人体炼成">human-transmutation</a> — 人体炼成</li><li><a href="/llm-wiki/concepts/等价交换">equivalent-exchange</a> — 等价交换</li></ul>',10)])])}const _=a(r,[["render",n]]);export{u as __pageData,_ as default};
